module top_module(
  input [3:0] A,
  input [3:0] B,
  input CIN,
  input CLK,
  output [3:0] SUM,
  output COUT
);reg [3:0] diff;
  reg cout;

  always @(posedge CLK) begin
    {cout, diff} <= A + B + CIN; // Directly using the addition operation
  end

  assign SUM = diff;
  assign COUT = cout;

endmodule
